import{_ as i,o as a,c as o,ag as t}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Informazioni su Dotfiles (IT)","titleTemplate":":title","description":"La nuova generazione di configurazione shell. Alte prestazioni, sicuro e AI-nativo. Gestito da Chezmoi.","frontmatter":{"title":"Informazioni su Dotfiles","description":"La nuova generazione di configurazione shell. Alte prestazioni, sicuro e AI-nativo. Gestito da Chezmoi.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Informazioni su Dotfiles preview","canonical":"/it/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Informazioni su Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"Informazioni su Dotfiles - Dotfiles (IT)","permalink":"/it/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, configurazione, automazione, macos, linux, rust, zellij, shell, terminale"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"La nuova generazione di configurazione shell. Alte prestazioni, sicuro e AI-nativo. Gestito da Chezmoi."},{"name":"twitter:title","content":"Informazioni su Dotfiles"},{"name":"og:title","content":"Informazioni su Dotfiles"},{"name":"og:description","content":"La nuova generazione di configurazione shell. Alte prestazioni, sicuro e AI-nativo. Gestito da Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/about/index.md","filePath":"it/about/index.md","lastUpdated":1773010926000}'),l={name:"it/about/index.md"};function n(s,e,r,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="informazioni-su-dotfiles" tabindex="-1">Informazioni su Dotfiles <a class="header-anchor" href="#informazioni-su-dotfiles" aria-label="Permalink to &quot;Informazioni su Dotfiles&quot;">​</a></h1><p>Lo standard moderno per la configurazione shell. Costruito su <strong>Chezmoi</strong> per una gestione sicura e multipiattaforma dell&#39;ambiente.</p><h2 id="scopri" tabindex="-1">Scopri <a class="header-anchor" href="#scopri" aria-label="Permalink to &quot;Scopri&quot;">​</a></h2><p>Dotfiles v0.2.495 trasforma il tuo terminale in uno spazio di lavoro potente e unificato. A differenza dei dotfiles legacy che si affidano a Makefile complessi o script di symlink, Dotfiles utilizza un approccio basato su template che e atomico, veloce e riproducibile.</p><h3 id="novita" tabindex="-1">Novita <a class="header-anchor" href="#novita" aria-label="Permalink to &quot;Novita&quot;">​</a></h3><ul><li><strong>Core Moderno</strong> — Alternative Rust ad alte prestazioni sostituiscono gli strumenti Unix legacy: <ul><li><strong>Atuin</strong> per la cronologia della shell</li><li><strong>Yazi</strong> per la gestione file</li><li><strong>Zellij</strong> per il multiplexing del terminale</li><li><strong>Ghostty</strong> per terminale con accelerazione GPU</li><li><strong>NeoVim</strong> per editing moderno</li></ul></li><li><strong>Sicurezza Nativa</strong> — Firma SSH completamente nativa senza agenti di terze parti</li><li><strong>Modalita Interattiva</strong> — Nuovo comando <code>dot learn</code> che ti guida attraverso le funzionalita</li></ul><h2 id="inizia" tabindex="-1">Inizia <a class="header-anchor" href="#inizia" aria-label="Permalink to &quot;Inizia&quot;">​</a></h2><h3 id="requisiti" tabindex="-1">Requisiti <a class="header-anchor" href="#requisiti" aria-label="Permalink to &quot;Requisiti&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong>, o <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> e <strong>Git</strong></li><li><strong>Chezmoi</strong> (installato automaticamente)</li><li><strong>Nerd Font</strong> (per le icone del terminale)</li></ul><h3 id="installa" tabindex="-1">Installa <a class="header-anchor" href="#installa" aria-label="Permalink to &quot;Installa&quot;">​</a></h3><p>Esegui un singolo comando per installare l&#39;intera suite:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>L&#39;installer:</p><ol><li>Installa il binario <code>chezmoi</code></li><li>Clona il repository</li><li>Installa i pacchetti richiesti tramite Homebrew (macOS) o Apt (Linux)</li><li>Applica la tua configurazione</li></ol><h3 id="esplora" tabindex="-1">Esplora <a class="header-anchor" href="#esplora" aria-label="Permalink to &quot;Esplora&quot;">​</a></h3><p>Dopo l&#39;installazione, riavvia il terminale ed esegui:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>Questo avvia un tour interattivo del tuo nuovo ambiente.</p><h2 id="personalizza" tabindex="-1">Personalizza <a class="header-anchor" href="#personalizza" aria-label="Permalink to &quot;Personalizza&quot;">​</a></h2><p>La tua configurazione risiede in <code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # Punto di ingresso shell</span></span>
<span class="line"><span>├── dot_config/             # XDG Base Config (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # Cronologia shell</span></span>
<span class="line"><span>│   ├── ghostty/            # Emulatore terminale</span></span>
<span class="line"><span>│   ├── git/                # Configurazione Git</span></span>
<span class="line"><span>│   ├── yazi/               # File manager</span></span>
<span class="line"><span>│   ├── zellij/             # Multiplexer terminale</span></span>
<span class="line"><span>│   ├── zsh/                # Configurazione Zsh</span></span>
<span class="line"><span>│   └── shell/              # Alias e percorsi condivisi</span></span>
<span class="line"><span>├── provision/              # Script del ciclo di vita</span></span>
<span class="line"><span>├── install.sh              # Installer universale</span></span>
<span class="line"><span>└── docs/                   # Documentazione</span></span></code></pre></div><h2 id="comandi-principali" tabindex="-1">Comandi principali <a class="header-anchor" href="#comandi-principali" aria-label="Permalink to &quot;Comandi principali&quot;">​</a></h2><p>La CLI <code>dot</code> offre 53 comandi organizzati per categoria.</p><h3 id="nucleo" tabindex="-1">Nucleo <a class="header-anchor" href="#nucleo" aria-label="Permalink to &quot;Nucleo&quot;">​</a></h3><ul><li><code>dot apply</code> — applica le modifiche alla configurazione.</li><li><code>dot sync</code> — recupera lo stato più recente del repository e lo applica.</li><li><code>dot update</code> — aggiorna il repository e preriscalda le cache.</li><li><code>dot add</code> — aggiunge nuovi file nel sorgente Chezmoi.</li><li><code>dot diff</code> — mostra le modifiche in sospeso prima dell&#39;applicazione.</li><li><code>dot status</code> — visualizza lo stato dei file gestiti.</li><li><code>dot remove</code> — rimuove un file dalla gestione e cancella la voce sorgente.</li><li><code>dot cd</code> — apre una shell nella directory sorgente di Chezmoi.</li><li><code>dot edit</code> — apre un file gestito nel tuo editor.</li><li><code>dot clean-cache</code> — svuota le cache transitorie.</li><li><code>dot prewarm</code> — precarica le cache per un avvio più veloce della shell.</li></ul><h3 id="diagnostica" tabindex="-1">Diagnostica <a class="header-anchor" href="#diagnostica" aria-label="Permalink to &quot;Diagnostica&quot;">​</a></h3><ul><li><code>dot doctor</code> — valida percorsi, strumenti e stato della shell.</li><li><code>dot heal</code> — ripara automaticamente lo stato mancante o danneggiato.</li><li><code>dot health</code> — esegue un controllo di salute leggero.</li><li><code>dot verify</code> — verifica l&#39;integrità dei file rispetto al sorgente.</li><li><code>dot scorecard</code> — mostra un punteggio di qualità della configurazione.</li><li><code>dot snapshot</code> — cattura lo stato attuale per confronto successivo.</li><li><code>dot smoke-test</code> — valida le toolchain principali end-to-end.</li><li><code>dot chaos</code> — inietta errori per testare l&#39;auto-riparazione.</li><li><code>dot bundle</code> — esporta un bundle di configurazione portabile.</li><li><code>dot rollback</code> — ripristina uno snapshot precedente.</li><li><code>dot drift</code> — rileva modifiche non autorizzate ai file gestiti.</li><li><code>dot history</code> — mostra il registro cronologico di apply/sync.</li><li><code>dot benchmark</code> — misura il tempo di avvio della shell.</li><li><code>dot perf</code> — profila l&#39;inizializzazione lenta della shell.</li></ul><h3 id="aspetto" tabindex="-1">Aspetto <a class="header-anchor" href="#aspetto" aria-label="Permalink to &quot;Aspetto&quot;">​</a></h3><ul><li><code>dot theme</code> — cambia lo schema colori del terminale.</li><li><code>dot wallpaper</code> — imposta lo sfondo del desktop (macOS).</li><li><code>dot fonts</code> — installa o aggiorna i Nerd Fonts.</li><li><code>dot tune</code> — regola la densità dell&#39;interfaccia e lo stile del prompt.</li></ul><h3 id="sicurezza" tabindex="-1">Sicurezza <a class="header-anchor" href="#sicurezza" aria-label="Permalink to &quot;Sicurezza&quot;">​</a></h3><ul><li><code>dot backup</code> — crea backup cifrati della configurazione.</li><li><code>dot encrypt-check</code> — verifica la cifratura dei segreti a riposo.</li><li><code>dot firewall</code> — configura le regole del firewall dell&#39;host.</li><li><code>dot telemetry</code> — controlla la telemetria di utilizzo anonima.</li><li><code>dot dns-doh</code> — abilita DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — blocca immediatamente lo schermo.</li><li><code>dot usb-safety</code> — limita il montaggio automatico di dispositivi USB.</li></ul><h3 id="segreti" tabindex="-1">Segreti <a class="header-anchor" href="#segreti" aria-label="Permalink to &quot;Segreti&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — inizializza il backend dei segreti (age / GPG).</li><li><code>dot secrets</code> — elenca le voci di segreti cifrati.</li><li><code>dot secrets-create</code> — crea un nuovo segreto cifrato.</li><li><code>dot ssh-key</code> — genera o ruota le coppie di chiavi SSH.</li><li><code>dot ssh-cert</code> — richiede un certificato SSH da una CA.</li></ul><h3 id="ia" tabindex="-1">IA <a class="header-anchor" href="#ia" aria-label="Permalink to &quot;IA&quot;">​</a></h3><ul><li><code>dot ai</code> — apre una sessione interattiva di assistente IA.</li><li><code>dot ai-setup</code> — configura le chiavi API per i fornitori di IA.</li><li><code>dot ai-query</code> — invia un prompt singolo a un modello di IA.</li><li>Wrapper di strumenti IA: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="strumenti" tabindex="-1">Strumenti <a class="header-anchor" href="#strumenti" aria-label="Permalink to &quot;Strumenti&quot;">​</a></h3><ul><li><code>dot tools</code> — elenca le sostituzioni CLI incluse e il loro stato.</li><li><code>dot new</code> — crea un nuovo file di alias o funzione.</li><li><code>dot sandbox</code> — apre una shell sandbox usa e getta.</li><li><code>dot keys</code> — mostra le scorciatoie da tastiera attuali.</li><li><code>dot learn</code> — avvia il tutorial interattivo.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — aggiorna Dotfiles all&#39;ultima versione.</li><li><code>dot packages</code> — elenca i pacchetti installati gestiti da Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — mostra informazioni su versione o utilizzo.</li></ul><h2 id="contribuisci" tabindex="-1">Contribuisci <a class="header-anchor" href="#contribuisci" aria-label="Permalink to &quot;Contribuisci&quot;">​</a></h2><p>Unisciti alla community. Consulta il nostro <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">Codice di Condotta</a> e le <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">Linee Guida per Contribuire</a>.</p>`,41)])])}const m=i(l,[["render",n]]);export{h as __pageData,m as default};
